import java.awt.*;
import java.awt.geom.*;
public class G2DState {
    // Graphics2D is obtained from a component's paintComponent or BufferedImage
    static void inspect(Graphics2D g2) {
        g2.setColor(Color.RED);
        g2.setStroke(new BasicStroke(3.0f));
        Color c = g2.getColor();
        System.out.println(c.equals(Color.RED));
        Stroke s = g2.getStroke();
        System.out.println(s instanceof BasicStroke);
        System.out.println(((BasicStroke)s).getLineWidth());
    }
}
